const body = $json;
const ALLOWED_OPS = ['issue','void','allowance','voidAllowance','query'];
for (const k of ['capability','candidates','op','input']) if (body[k] == null) throw new Error(`${k} required`);
if (!Array.isArray(body.candidates) || body.candidates.length === 0) throw new Error('candidates must be non-empty array');
if (!ALLOWED_OPS.includes(body.op)) throw new Error(`op must be one of: ${ALLOWED_OPS.join(', ')}`);
return [{ json: {
  correlationId: body.correlationId || `inv-route-${Date.now()}-${Math.floor(Math.random()*1e6)}`,
  capability: body.capability,
  candidates: body.candidates,
  op: body.op,
  input: body.input
}}];

const state = $node['Validate + stamp'].json;
const statusCode = Number($json.statusCode ?? 0);
const body = $json.body ?? $json;
const ok = statusCode >= 200 && statusCode < 300;
return [{ json: { ...state, statusCode, ok, response: body } }];
